        for lag in range(1, max_lags + 1):
            cov = np.mean(z2_demean[lag:] * z2_demean[:-lag])
            acf_vals[lag - 1] = cov / var_z2 if var_z2 > 0 else 0.0

        lags = np.arange(1, max_lags + 1)
