        ax4.set_title("Histogram of Standardized Residuals")
        ax4.set_xlabel(r"$z_t$")
        ax4.set_ylabel("Density")
        ax4.legend(loc="upper right", framealpha=0.8)

        fig.suptitle(
            title or "Model Diagnostics",
            fontsize=theme.font_sizes.get("title", 14),
            y=1.02,
        )
        fig.tight_layout()
        return fig


