        ax2.set_title(r"ACF of $z_t^2$")
        ax2.set_xlabel("Lag")
        ax2.set_ylabel("ACF")

        # --- Panel 3: QQ-Plot ---
        ax3 = axes[1, 0]
        sorted_z = np.sort(z)
        n = len(sorted_z)
        theoretical_q = stats.norm.ppf((np.arange(1, n - 1) - 0.5) / n)
